function calculateImpact(inputs) {
    const {
        initialWeeklyWasteKg,
        reductionPercentage,
        avgCostPerKg,
        foodWasteCarbonFactorPerKg,
        waterFootprintPerKgFood,
        landUseFactorSqMPerKg
    } = inputs;

    // Validate essential inputs
    if (initialWeeklyWasteKg === undefined || initialWeeklyWasteKg < 0 ||
        reductionPercentage === undefined || reductionPercentage < 0 || reductionPercentage > 100 ||
        avgCostPerKg === undefined || avgCostPerKg < 0) {
        return {
            annualFinancialSavings: 0,
            annualWasteReducedKg: 0,
            annualCO2eReducedKg: 0,
            annualWaterSavingsLiters: 0,
            annualLandSavingsSqM: 0
        };
    }

    // Default environmental factors if not provided (user can override)
    const carbonFactorFoodWaste = foodWasteCarbonFactorPerKg !== undefined && foodWasteCarbonFactorPerKg >= 0 ? foodWasteCarbonFactorPerKg : 2.5; // kg CO2e/kg food waste (lifecycle incl. methane from decomposition)
    const waterFactorFood = waterFootprintPerKgFood !== undefined && waterFootprintPerKgFood >= 0 ? waterFootprintPerKgFood : 2000; // liters/kg food (global average water footprint)
    const landFactor = landUseFactorSqMPerKg !== undefined && landUseFactorSqMPerKg >= 0 ? landUseFactorSqMPerKg : 2.5; // sq meters/kg food (approx. average for diverse food production)

    // Annual calculations
    const annualWeeks = 52;
    const annualWasteKg = initialWeeklyWasteKg * annualWeeks;
    const actualReductionPercentage = Math.min(Math.max(reductionPercentage, 0), 100) / 100; // Ensure 0-100% and convert to decimal

    const annualWasteReducedKg = annualWasteKg * actualReductionPercentage;

    // Financial Savings
    const annualFinancialSavings = annualWasteReducedKg * avgCostPerKg;

    // Environmental Impact Savings
    // 1. CO2e Savings: Direct lifecycle emissions reduction from avoiding food waste.
    const annualCO2eReducedKg = annualWasteReducedKg * carbonFactorFoodWaste;

    // 2. Water Savings: Water footprint reduction from avoiding food waste.
    const annualWaterSavingsLiters = annualWasteReducedKg * waterFactorFood;

    // 3. Land Use Savings: Land area reduction from avoiding food waste.
    const annualLandSavingsSqM = annualWasteReducedKg * landFactor;

    return {
        annualFinancialSavings: parseFloat(annualFinancialSavings.toFixed(2)),
        annualWasteReducedKg: parseFloat(annualWasteReducedKg.toFixed(1)),
        annualCO2eReducedKg: parseFloat(annualCO2eReducedKg.toFixed(1)),
        annualWaterSavingsLiters: parseFloat(annualWaterSavingsLiters.toFixed(0)),
        annualLandSavingsSqM: parseFloat(annualLandSavingsSqM.toFixed(1))
    };
}
